from __future__ import annotations

from typing import Any, Mapping


class CursorAgentError(Exception):
    """Base class for all Python Cursor SDK errors.

    Transport wrappers use native ``__cause__`` chaining for local Python
    exceptions. The explicit ``cause`` field is for upstream errors described
    by a Connect payload rather than a local exception object.
    """

    def __init__(
        self,
        message: str,
        *,
        code: str | None = None,
        status: int | None = None,
        details: list[Mapping[str, Any]] | None = None,
        is_retryable: bool = False,
        cause: BaseException | None = None,
        proto_error_code: str | None = None,
        request_id: str | None = None,
        headers: Mapping[str, str] | None = None,
        retry_after: str | None = None,
    ) -> None:
        super().__init__(message)
        self.message = message
        self.code = code
        self.status = status
        self.details = list(details or [])
        self.is_retryable = is_retryable
        self.cause = cause
        self.proto_error_code = proto_error_code
        self.request_id = request_id
        self.headers = dict(headers or {})
        self.retry_after = retry_after

    @property
    def status_code(self) -> int | None:
        return self.status

    def __str__(self) -> str:
        if self.code:
            return f"{self.code}: {self.message}"
        return self.message

    def __repr__(self) -> str:
        return (
            f"{self.__class__.__name__}({self.message!r}, "
            f"code={self.code!r}, status={self.status!r}, "
            f"request_id={self.request_id!r})"
        )


class CursorSDKError(CursorAgentError):
    """Backward-compatible alias root for pre-parity callers."""


class AuthenticationError(CursorSDKError):
    pass


class PermissionDeniedError(AuthenticationError):
    pass


class RateLimitError(CursorSDKError):
    pass


class ConfigurationError(CursorSDKError):
    pass


class AgentBusyError(CursorSDKError):
    pass


class BadRequestError(ConfigurationError):
    pass


class IntegrationNotConnectedError(ConfigurationError):
    def __init__(
        self,
        message: str,
        *,
        provider: str,
        help_url: str,
        **kwargs: Any,
    ) -> None:
        super().__init__(message, **kwargs)
        self.provider = provider
        self.help_url = help_url


class NetworkError(CursorSDKError):
    pass


class APITimeoutError(NetworkError):
    pass


class InternalServerError(NetworkError):
    pass


class NotFoundError(CursorSDKError):
    pass


class AgentNotFoundError(NotFoundError):
    """The requested agent does not exist (or isn't visible under the cwd)."""


class UnsupportedRunOperationError(ConfigurationError):
    def __init__(self, operation: str, message: str | None = None) -> None:
        super().__init__(
            message or f"Run operation {operation!r} is not supported",
            code="unsupported_run_operation",
        )
        self.operation = operation


def error_from_connect_payload(
    error: Mapping[str, Any],
    *,
    status: int | None = None,
    cause: BaseException | None = None,
) -> CursorSDKError:
    message = str(error.get("message", "Bridge request failed"))
    code = str(error.get("code", "")) or None
    details = list(error.get("details") or [])
    sdk_details = _find_sdk_error_details(details)
    if sdk_details is not None:
        message = str(sdk_details.get("message") or message)
        proto_code = str(sdk_details.get("sdkErrorCode") or "")
        request_id = sdk_details.get("requestId")
        retry_after = sdk_details.get("retryAfter")
        help_url_raw = sdk_details.get("helpUrl")
        provider_raw = sdk_details.get("provider")
        help_url = str(help_url_raw) if help_url_raw else ""
        provider = str(provider_raw) if provider_raw else ""
        kwargs = {
            "code": code,
            "status": status,
            "details": details,
            "is_retryable": bool(sdk_details.get("retryAfter")),
            "cause": cause,
            "proto_error_code": proto_code or None,
            "request_id": str(request_id) if request_id else None,
            "retry_after": str(retry_after) if retry_after else None,
        }
        if _is_integration_error(proto_code, code):
            if help_url and provider:
                return IntegrationNotConnectedError(
                    message,
                    provider=provider,
                    help_url=help_url,
                    **kwargs,
                )
            return ConfigurationError(message, **kwargs)
        return _error_class_for_code(proto_code, code)(message, **kwargs)
    return _error_class_for_code("", code)(
        message,
        code=code,
        status=status,
        details=details,
        cause=cause,
    )


def _find_sdk_error_details(
    details: list[Any],
) -> Mapping[str, Any] | None:
    # Walk twice: prefer entries that carry an actual sdkErrorCode (i.e. the
    # full SdkErrorDetails payload). Fall back to requestId-only entries
    # (e.g. tracing/metadata details) so we still surface the request id when
    # nothing richer is attached.
    fallback: Mapping[str, Any] | None = None
    for detail in details:
        for candidate in _detail_candidates(detail):
            if "sdkErrorCode" in candidate:
                return candidate
            if fallback is None and "requestId" in candidate:
                fallback = candidate
    return fallback


def _detail_candidates(detail: Any) -> list[Mapping[str, Any]]:
    # Connect details come over JSON without a strict type, so the entry can be
    # a raw string/int/null when the bridge serializes a malformed payload.
    # Skip anything that isn't a Mapping rather than crashing on .get().
    if not isinstance(detail, Mapping):
        return []
    candidates: list[Mapping[str, Any]] = [detail]
    debug = detail.get("debug")
    if isinstance(debug, Mapping):
        candidates.append(debug)
    value = detail.get("value")
    if isinstance(value, Mapping):
        candidates.append(value)
    return candidates


def _is_integration_error(proto_code: str, connect_code: str | None) -> bool:
    normalized = _normalize_error_code(proto_code or connect_code or "")
    return normalized in {
        "integration_not_connected",
        "repository_access",
        "pr_resolution_failed",
    }


def _normalize_error_code(code: str) -> str:
    return code.removeprefix("SDK_ERROR_CODE_").lower()


def _error_class_for_code(
    proto_code: str,
    connect_code: str | None,
) -> type[CursorSDKError]:
    normalized = _normalize_error_code(proto_code or connect_code or "")
    if normalized in {
        "unauthorized",
        "unauthenticated",
        "api_key_not_found",
    }:
        return AuthenticationError
    if normalized in {"role_forbidden", "permission_denied", "forbidden"}:
        return PermissionDeniedError
    if normalized in {
        "rate_limit_exceeded",
        "usage_limit_exceeded",
        "resource_exhausted",
        "rate_limited",
    }:
        return RateLimitError
    if normalized in {
        "invalid_argument",
        "validation_error",
        "bad_request",
    }:
        return BadRequestError
    if normalized in {
        "invalid_model",
        "invalid_branch_name",
        # Generic Connect 'not_found' (wrong endpoint or unknown resource type)
        # is a configuration issue, not an unknown agent specifically; mirror
        # the TS SDK's mapping. Resource-specific codes below stay typed.
        "not_found",
    }:
        return ConfigurationError
    if normalized == "agent_busy":
        return AgentBusyError
    if normalized == "agent_not_found":
        return AgentNotFoundError
    if normalized == "run_not_found":
        return NotFoundError
    if normalized == "timeout":
        return APITimeoutError
    if normalized in {
        "upstream_error",
        "internal_error",
        "internal",
        "internal_server_error",
    }:
        return InternalServerError
    if normalized in {
        "unavailable",
        "deadline_exceeded",
        "data_loss",
    }:
        return NetworkError
    if not normalized or normalized == "unspecified":
        return CursorSDKError
    return CursorSDKError
